const ICONS: Record<string, TechIcon> = {
  ...CUSTOM,
  langgraph: fromSi(siLanggraph),
  spacy: fromSi(siSpacy),
  tensorflow: fromSi(siTensorflow),
  pandas: fromSi(siPandas),
  scikitlearn: fromSi(siScikitlearn),
  postgresql: fromSi(siPostgresql),
  apachespark: fromSi(siApachespark),
  go: fromSi(siGo),
  nodedotjs: fromSi(siNodedotjs),
  express: fromSi(siExpress),
  docker: fromSi(siDocker),
  openjdk: fromSi(siOpenjdk),
  apacheairflow: fromSi(siApacheairflow),
  googlecloud: fromSi(siGooglecloud),
  python: fromSi(siPython),
  typescript: fromSi(siTypescript),
  react: fromSi(siReact),
  fastapi: fromSi(siFastapi),
  git: fromSi(siGit),
  n8n: fromSi(siN8n),
  zapier: fromSi(siZapier),
  vercel: fromSi(siVercel),
}

/** Normalized display name → icon lookup key. */
const ALIASES: Record<string, string> = {
  golang: 'go',
  nodejs: 'nodedotjs',
  java: 'openjdk',
  spark: 'apachespark',
  awspersonalize: 'aws',
}

export function getTechIcon(name: string): TechIcon | null {
  const key = normalizeKey(name)
  const lookup = ALIASES[key] ?? key
  return ICONS[lookup] ?? null
}
